    fn tmp(name: &str) -> PathBuf {
        std::env::temp_dir().join(name)
    }

    fn paths(name: &str) -> (PathBuf, PathBuf) {
        (tmp(&format!("{}.nxr", name)), tmp(&format!("{}.nxr-wal", name)))
    }

    fn cleanup(db: &PathBuf, wal: &PathBuf) {
        let _ = std::fs::remove_file(db);
        let _ = std::fs::remove_file(wal);
    }

    // Test 1 — write then read from WAL: data comes from WAL, not main file
    #[test]
    fn test_wal_write_read_round_trip() {
        let (db, wal) = paths("test_wal_write_read_round_trip");
        cleanup(&db, &wal);

        let inner = RegularPageStore::create(&db).unwrap();
        let mut store = WALPageStore::create(inner, &wal).unwrap();

        let mut page = [0u8; PAGE_SIZE];
        page[0..5].copy_from_slice(b"hello");
        store.write_page(PageId(2), &page, false).unwrap();

        let mut buf = [0u8; PAGE_SIZE];
        store.read_page(PageId(2), &mut buf, false).unwrap();

        assert_eq!(&buf[0..5], b"hello");
        cleanup(&db, &wal);
    }

    // Test 2 — read falls through to inner: page not in WAL comes from main file
    #[test]
    fn test_wal_read_falls_through_to_inner() {
        let (db, wal) = paths("test_wal_read_falls_through_to_inner");
        cleanup(&db, &wal);

        let inner = RegularPageStore::create(&db).unwrap();
        let mut store = WALPageStore::create(inner, &wal).unwrap();

        // Page 0 is the main file header — never written to WAL.
        // Falls through to inner which holds the "NXRA" header written at create time.
        let mut buf = [0u8; PAGE_SIZE];
        store.read_page(PageId(0), &mut buf, false).unwrap();

        // NexoraHeader.magic is at byte offset 48 (page_header:32 + version:4 + page_size:4 + footer_page_id:8)
        assert_eq!(&buf[48..52], b"NXRA");
        cleanup(&db, &wal);
    }

