    // Test 4 — checkpoint writes pages to main file and clears WAL
    #[test]
    fn test_wal_checkpoint() {
        let (db, wal) = paths("test_wal_checkpoint");
        cleanup(&db, &wal);

        {
            let inner = RegularPageStore::create(&db).unwrap();
            let mut store = WALPageStore::create(inner, &wal).unwrap();

            let mut page = [0u8; PAGE_SIZE];
            page[0..5].copy_from_slice(b"hello");
            store.write_page(PageId(2), &page, false).unwrap();
            store.commit().unwrap();
            store.checkpoint().unwrap();
        }

        // WAL file should be exactly the header size — all frames cleared.
        let wal_size = std::fs::metadata(&wal).unwrap().len();
        assert_eq!(wal_size as usize, std::mem::size_of::<WALHeader>());

        // Main file should have the page.
        let mut inner = RegularPageStore::open(&db).unwrap();
        let mut buf = [0u8; PAGE_SIZE];
        inner.read_page(PageId(2), &mut buf, false).unwrap();
        assert_eq!(&buf[0..5], b"hello");

        cleanup(&db, &wal);
    }

